import { execution } from '@dynatrace-sdk/automation-utils';
import { queryExecutionClient } from '@dynatrace-sdk/client-query';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);

  // ── Debug: log all available event keys ───────────────────
  const event = ex.params?.event || ex.event || ex.params || {};
  console.log('Trigger event keys: ' + JSON.stringify(Object.keys(event)));
  console.log('Trigger event (first 2000 chars): ' + JSON.stringify(event).substring(0, 2000));

  // ── Extract Davis problem fields ──────────────────────────
  // Davis problem trigger provides these standard fields:
  const problemId     = event['display_id'] || event['event.id'] || event['ProblemID'] || event['problemId'] || event['id'] || 'unknown';
  const problemTitle  = event['event.name'] || event['title'] || event['ProblemTitle'] || event['problemTitle'] || 'Unknown Problem';
  const severity      = event['event.category'] || event['severity'] || event['Severity'] || event['SeverityLevel'] || 'ERROR';
  const entityId      = event['entity_id'] || event['dt.entity.process_group'] || (event['affected_entity_ids'] || [])[0] || event['RootCauseEntity'] || '';
  const entityName    = event['entity_name'] || event['ImpactedEntity'] || event['RootCauseEntityName'] || '';
  const rootCauseId   = event['root_cause_entity_id'] || event['RootCauseEntity'] || entityId;
  const rootCauseName = event['root_cause_entity_name'] || event['RootCauseEntityName'] || entityName;
  const impactLevel   = event['impact_level'] || event['ImpactLevel'] || event['ProblemImpact'] || 'SERVICES';
  const startTime     = event['start_time'] || event['StartTime'] || Date.now();

  console.log('=== Davis Problem Detected ===');
  console.log(`Problem: ${problemId} — ${problemTitle}`);
  console.log(`Severity: ${severity} | Impact: ${impactLevel}`);
  console.log(`Root Cause Entity: ${rootCauseName} (${rootCauseId})`);

  // ── DQL: Recent error logs tied to this entity ────────────
  let recentErrors = [];
  try {
    const errorQuery = entityId
      ? `fetch logs
| filter loglevel == "ERROR" OR status == "ERROR"
| filter dt.entity.process_group_instance == "${entityId}" OR dt.entity.service == "${entityId}"
| sort timestamp desc
| limit 15
| fields timestamp, content, loglevel, dt.entity.service`
      : `fetch logs
| filter loglevel == "ERROR" OR status == "ERROR"
| sort timestamp desc
| limit 15
| fields timestamp, content, loglevel, dt.entity.service`;

    const resp = await queryExecutionClient.queryExecute({
      body: { query: errorQuery, requestTimeoutMilliseconds: 15000, maxResultRecords: 15 }
    });
    recentErrors = (resp?.result?.records || []).map(r => ({
      time: r.timestamp,
      message: String(r.content || '').substring(0, 200),
      service: r['dt.entity.service'] || ''
    }));
  } catch (e) {
    console.log('Error log query failed: ' + e.message);
  }

  // ── DQL: Affected services / process groups ───────────────
  let affectedServices = [];
  try {
    const svcQuery = `fetch dt.entity.service
| fieldsAdd tags
| filter matchesPhrase(toString(tags), "BizObs") OR matchesPhrase(toString(tags), "journey")
| fields entity.name, id
| limit 10`;

    const resp = await queryExecutionClient.queryExecute({
      body: { query: svcQuery, requestTimeoutMilliseconds: 10000, maxResultRecords: 10 }
    });
    affectedServices = (resp?.result?.records || []).map(r => ({
      name: r['entity.name'],
      id: r.id
    }));
  } catch (e) {
    console.log('Service topology query failed: ' + e.message);
  }

  // ── DQL: Feature-flag / chaos deployment events ───────────
  let chaosEvents = [];
  try {
    const chaosQuery = `fetch events
| filter event.kind == "CUSTOM_DEPLOYMENT" OR event.kind == "CUSTOM_INFO"
| filter matchesPhrase(event.name, "feature") OR matchesPhrase(event.name, "chaos") OR matchesPhrase(event.name, "nemesis") OR matchesPhrase(event.name, "error_injection")
| sort timestamp desc
| limit 5
| fields timestamp, event.name, event.kind, dt.entity.process_group`;

    const resp = await queryExecutionClient.queryExecute({
      body: { query: chaosQuery, requestTimeoutMilliseconds: 10000, maxResultRecords: 5 }
    });
    chaosEvents = (resp?.result?.records || []).map(r => ({
      time: r.timestamp,
      name: r['event.name'],
      kind: r['event.kind']
    }));
  } catch (e) {
    console.log('Chaos event query failed: ' + e.message);
  }

  // ── DQL: Business events impact (revenue) ─────────────────
  let businessImpact = null;
  try {
    const bizQuery = `fetch bizevents
| filter event.type == "journey_step_failed" OR event.type == "journey_error"
| filter toTimestamp(now()) - timestamp < duration("30m")
| summarize errorCount = count()
| fields errorCount`;

    const resp = await queryExecutionClient.queryExecute({
      body: { query: bizQuery, requestTimeoutMilliseconds: 10000, maxResultRecords: 1 }
    });
    const rec = resp?.result?.records?.[0];
    if (rec) {
      businessImpact = {
        failedTransactions: rec.errorCount || 0
      };
    }
  } catch (e) {
    console.log('Business impact query failed: ' + e.message);
  }

  // ── Build context summary ─────────────────────────────────
  const contextSummary = [
    `Problem ${problemId}: ${problemTitle}`,
    `Severity: ${severity} | Impact: ${impactLevel}`,
    `Root Cause: ${rootCauseName} (${rootCauseId})`,
    `Recent errors: ${recentErrors.length}`,
    `Affected services: ${affectedServices.map(s => s.name).join(', ') || 'unknown'}`,
    `Chaos events in last 30m: ${chaosEvents.length}`,
    businessImpact ? `Business impact: ${businessImpact.failedTransactions} failed transactions in last 30m` : 'Business impact: unknown'
  ].join('\n');

  console.log('--- Context Summary ---');
  console.log(contextSummary);

  return {
    problem_id: problemId,
    title: problemTitle,
    severity: severity,
    impact_level: impactLevel,
    entity_id: entityId,
    entity_name: entityName,
    root_cause_entity_id: rootCauseId,
    root_cause_entity_name: rootCauseName,
    start_time: startTime,
    recent_errors: recentErrors,
    recent_errors_count: recentErrors.length,
    affected_services: affectedServices,
    chaos_events: chaosEvents,
    chaos_events_count: chaosEvents.length,
    business_impact: businessImpact,
    context_summary: contextSummary
  };
}

import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);
  const ctx = ex.taskResults?.get_problem_details;
  const problemId = ctx?.problem_id || 'unknown';

  console.log(`Querying Davis AI root cause for problem: ${problemId}`);

  let davisAnalysis = {
    root_cause: 'Unable to determine',
    confidence: 0,
    evidence: [],
    affected_entities: [],
    management_zone: '',
    impact_analysis: ''
  };

  try {
    // Fetch full problem details from Davis — includes root cause entity,
    // evidenceDetails, impactAnalysis, and affectedEntities
    const problem = await problemsClient.getProblem({
      problemId: problemId
    });

    console.log(`Davis problem status: ${problem.status}`);
    console.log(`Davis display ID: ${problem.displayId}`);
    console.log(`Davis root cause entity: ${problem.rootCauseEntity?.name || 'N/A'}`);
    console.log(`Davis impact level: ${problem.impactLevel}`);
    console.log(`Davis severity: ${problem.severityLevel}`);

    // Extract Davis evidence details
    const evidence = problem.evidenceDetails?.details || [];
    const evidenceSummary = evidence.map(e => {
      const eType = e.evidenceType || 'UNKNOWN';
      const eEntity = e.entity?.name || 'unknown';
      const eField = e.displayName || '';
      return `${eType}: ${eField} on ${eEntity}`;
    });
    console.log(`Davis evidence items: ${evidence.length}`);

    // Extract affected entities
    const affected = problem.affectedEntities || [];
    const affectedNames = affected.map(a => `${a.name} (${a.entityId?.type || 'unknown'})`);

    // Extract management zone
    const mgmtZones = problem.managementZones || [];
    const mgmtZoneNames = mgmtZones.map(z => z.name).join(', ');

    // Build root cause description from Davis
    const rootCauseEntity = problem.rootCauseEntity;
    let rootCauseDescription = 'Unknown';
    if (rootCauseEntity) {
      rootCauseDescription = `${rootCauseEntity.name} (${rootCauseEntity.entityId?.type || 'entity'})`;
    }

    // Impact analysis
    const impactAnalysis = [
      `Impact Level: ${problem.impactLevel || 'N/A'}`,
      `Severity: ${problem.severityLevel || 'N/A'}`,
      `Affected entities: ${affected.length}`,
      `Management zones: ${mgmtZoneNames || 'none'}`
    ].join('; ');

    davisAnalysis = {
      root_cause: rootCauseDescription,
      confidence: evidence.length > 0 ? 0.85 : 0.5,
      evidence: evidenceSummary,
      affected_entities: affectedNames,
      management_zone: mgmtZoneNames,
      impact_analysis: impactAnalysis
    };

    console.log(`=== Davis Root Cause Analysis ===`);
    console.log(`Root Cause: ${davisAnalysis.root_cause}`);
    console.log(`Confidence: ${davisAnalysis.confidence}`);
    console.log(`Evidence: ${JSON.stringify(evidenceSummary)}`);
    console.log(`Impact: ${impactAnalysis}`);

  } catch (err) {
    console.log(`Davis API call failed: ${err.message}`);
    console.log('Falling back to context-only analysis');

    davisAnalysis.root_cause = ctx?.root_cause_entity_name || 'Unknown — Davis API unavailable';
    davisAnalysis.confidence = 0.3;
    davisAnalysis.evidence = ctx?.recent_errors?.slice(0, 3).map(e => e.message) || [];
  }

  return davisAnalysis;
}

import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';
import { businessEventsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);
  const problemCtx   = ex.taskResults?.get_problem_details;
  const davisCtx     = ex.taskResults?.get_davis_root_cause;
  const fixitResult  = ex.taskResults?.trigger_fixit_agent;

  const problemId = problemCtx?.problem_id || 'unknown';
  const statusCode = fixitResult?.statusCode || 0;
  const body = fixitResult?.body || {};
  const fixSuccess = body.success === true;
  const runId = body.runId || 'unknown';
  const message = body.message || 'No response';

  // ── Parse Fix-It results ──────────────────────────────────
  const fixesExecuted = body.result?.fixesExecuted || [];
  const diagnosis     = body.result?.diagnosis || {};
  const durationMs    = body.result?.totalDurationMs || 0;

  console.log(`=== Fix-It Agent Verification ===`);
  console.log(`Problem: ${problemId}`);
  console.log(`Fix-It HTTP Status: ${statusCode}`);
  console.log(`Success: ${fixSuccess}`);
  console.log(`Run ID: ${runId}`);
  console.log(`Message: ${message}`);
  console.log(`Root Cause (Davis): ${davisCtx?.root_cause || 'N/A'}`);
  console.log(`Root Cause (Agent): ${diagnosis.rootCause || 'N/A'}`);
  console.log(`Confidence: ${diagnosis.confidence || davisCtx?.confidence || 'N/A'}`);
  console.log(`Duration: ${durationMs}ms`);
  console.log(`Fixes Executed: ${fixesExecuted.length}`);

  for (const fix of fixesExecuted) {
    console.log(`  -> ${fix.fixType}: ${fix.target} — ${fix.success ? 'SUCCESS' : 'FAILED'}`);
  }

  // ── Check if Davis problem has closed ──────────────────────
  let problemClosed = false;
  try {
    const problem = await problemsClient.getProblem({ problemId });
    problemClosed = problem.status === 'CLOSED';
    console.log(`Davis problem status after fix: ${problem.status}`);
  } catch (e) {
    console.log(`Could not verify problem status: ${e.message}`);
  }

  // ── Send remediation BizEvent for dashboard tracking ──────
  try {
    const bizEvent = {
      'event.type': 'fixit_remediation_complete',
      'event.provider': 'bizobs-fixit-agent',
      'problem.id': problemId,
      'problem.title': problemCtx?.title || '',
      'problem.severity': problemCtx?.severity || '',
      'davis.root_cause': davisCtx?.root_cause || '',
      'davis.confidence': String(davisCtx?.confidence || 0),
      'agent.diagnosis': diagnosis.rootCause || '',
      'agent.confidence': String(diagnosis.confidence || 0),
      'remediation.success': String(fixSuccess),
      'remediation.fixes_count': String(fixesExecuted.length),
      'remediation.fixes_summary': fixesExecuted.map(f => `${f.fixType}:${f.target}=${f.success}`).join(', '),
      'remediation.duration_ms': String(durationMs),
      'remediation.run_id': runId,
      'remediation.problem_closed': String(problemClosed),
      'workflow.execution_id': execution_id
    };

    await businessEventsClient.ingest({
      body: bizEvent,
      type: 'application/json'
    });
    console.log('Remediation BizEvent sent successfully');
  } catch (e) {
    console.log(`BizEvent ingest failed: ${e.message}`);
  }

  // ── Build human-readable summary ──────────────────────────
  const fixesSummary = fixesExecuted.length > 0
    ? fixesExecuted.map(f => `  * ${f.fixType} -> ${f.target}: ${f.success ? 'SUCCESS' : 'FAILED'}`).join('\n')
    : '  * No fixes executed';

  const summary = [
    `Fix-It Agent Remediation Report`,
    `================================`,
    `Problem: ${problemId} — ${problemCtx?.title || 'Unknown'}`,
    `Severity: ${problemCtx?.severity || 'N/A'} | Impact: ${problemCtx?.impact_level || 'N/A'}`,
    ``,
    `Davis Root Cause: ${davisCtx?.root_cause || 'N/A'}`,
    `Agent Diagnosis: ${diagnosis.rootCause || 'N/A'}`,
    `Confidence: ${((diagnosis.confidence || davisCtx?.confidence || 0) * 100).toFixed(0)}%`,
    ``,
    `Fixes Applied:`,
    fixesSummary,
    ``,
    `Result: ${fixSuccess ? 'Remediation successful' : 'Remediation failed'}`,
    `Problem Closed: ${problemClosed ? 'Yes' : 'Not yet'}`,
    `Duration: ${durationMs}ms`,
    `Run ID: ${runId}`
  ].join('\n');

  console.log('\n' + summary);

  return {
    success: fixSuccess,
    problem_closed: problemClosed,
    run_id: runId,
    problem_id: problemId,
    message: message,
    davis_root_cause: davisCtx?.root_cause || 'N/A',
    agent_root_cause: diagnosis.rootCause || 'N/A',
    confidence: diagnosis.confidence || davisCtx?.confidence || 0,
    fixes_count: fixesExecuted.length,
    fixes_summary: fixesExecuted.map(f => `${f.fixType}:${f.target}=${f.success}`).join(', '),
    duration_ms: durationMs,
    remediation_summary: summary
  };
}
